# Example: AWS Config rule to continuously verify CloudTrail is enabled
{
  "ConfigRuleName": "cloud-trail-enabled",
  "Source": {
    "Owner": "AWS",
    "SourceIdentifier": "CLOUD_TRAIL_ENABLED"
  },
  "InputParameters": "{\"s3BucketName\": \"my-audit-bucket\"}"
}

# Check compliance status across all accounts in the organization
aws configservice describe-compliance-by-config-rule \
  --config-rule-names cloud-trail-enabled \
  --compliance-types NON_COMPLIANT
